var __index = {"config":{"lang":["en"],"separator":"[\\s\\-]+","pipeline":[" "],"fields":{"title":{"boost":1000.0},"text":{"boost":1.0},"tags":{"boost":1000000.0}}},"docs":[{"location":"index.html","title":"AI Agent with MCP","text":""},{"location":"index.html#scope","title":"Scope","text":"<ul> <li>AI Agent usage</li> <li>MCP Tool integration</li> <li>GitHub automation</li> <li>Local TEST execution</li> <li>CI/CD/CT workflow</li> </ul>"},{"location":"index.html#entry-points","title":"Entry Points","text":"Area Document Architecture System Design MCP MCP Gateway Local Tooling MCP Server-Local GitHub Integration MCP Server-Github"},{"location":"index.html#document-groups","title":"Document Groups","text":"Group Coverage Architecture system structure, automation, role split Agents Claude, Codex, Ollama MCP Gateway, Local MCP Server, GitHub MCP Server Envs Windows, WSL2, GitHub operation docs Logs run records"},{"location":"index.html#reading-order","title":"Reading Order","text":"<ol> <li>System Design</li> <li>MCP Gateway</li> <li>MCP Server-Local</li> <li>MCP Server-Github</li> <li>Agent documents</li> <li>Environment documents</li> </ol>"},{"location":"index.html#automation","title":"Automation","text":"<ul> <li>runner TEST Request</li> <li>direct TEST Request</li> <li>GitHub comment / artifact / log / JSON trace</li> </ul> <p>Reference:</p> <ul> <li>System Design</li> </ul>"},{"location":"agents/claude.html","title":"Agent: Claude","text":""},{"location":"agents/claude.html#purpose","title":"Purpose","text":"<ul> <li>reasoning</li> <li>long-context analysis</li> <li>document writing</li> <li>architecture discussion</li> </ul>"},{"location":"agents/claude.html#when-to-use","title":"When to Use","text":"<ul> <li>structure design</li> <li>long document review</li> <li>workflow organization</li> <li>change plan review before implementation</li> </ul>"},{"location":"agents/claude.html#model","title":"Model","text":"Item Value Provider Anthropic Default Model <code>claude-sonnet-4-6</code> Higher Tier <code>claude-opus-4-6</code> API Anthropic Messages API"},{"location":"agents/claude.html#configuration","title":"Configuration","text":"<pre><code>{\n  \"agent\": \"claude\",\n  \"model\": \"claude-sonnet-4-6\",\n  \"max_tokens\": 4096,\n  \"system_prompt\": \"You are a helpful assistant with strong reasoning skills.\"\n}\n</code></pre>"},{"location":"agents/claude.html#setup","title":"Setup","text":""},{"location":"agents/claude.html#rule-files","title":"Rule Files","text":"Path Role <code>claude.md</code> project rule file <code>C:\\\\Users\\\\&lt;user&gt;\\\\.claude\\\\projects\\\\d--works-projects-local-ai-agent-mcp\\\\memory</code> project memory"},{"location":"agents/claude.html#authentication","title":"Authentication","text":"<p>Method 1:</p> <pre><code>claude auth login\n</code></pre> <p>Method 2:</p> <pre><code>export ANTHROPIC_API_KEY=\"sk-ant-...\"\n</code></pre> <p>Method 3:</p> <pre><code>$env:ANTHROPIC_API_KEY = \"sk-ant-...\"\n</code></pre>"},{"location":"agents/claude.html#verify","title":"Verify","text":"<pre><code>claude auth status\nclaude -p \"hello\"\n</code></pre>"},{"location":"agents/claude.html#mcp-notes","title":"MCP Notes","text":"<ul> <li>MCP tool usage available</li> <li>strong on long-context reasoning work</li> <li>better fit for analysis and design than local execution itself</li> </ul>"},{"location":"agents/codex.html","title":"Agent: Codex","text":""},{"location":"agents/codex.html#purpose","title":"Purpose","text":"<ul> <li>code generation</li> <li>patch writing</li> <li>refactoring</li> <li>implementation support</li> </ul>"},{"location":"agents/codex.html#when-to-use","title":"When to Use","text":"<ul> <li>code creation</li> <li>existing code updates</li> <li>boilerplate cleanup</li> <li>test code draft</li> </ul>"},{"location":"agents/codex.html#model","title":"Model","text":"Item Value Provider OpenAI Default Model <code>gpt-4o</code> Role code-focused generation API OpenAI API"},{"location":"agents/codex.html#configuration","title":"Configuration","text":"<pre><code>{\n  \"agent\": \"codex\",\n  \"model\": \"gpt-4o\",\n  \"temperature\": 0.2,\n  \"max_tokens\": 2048,\n  \"system_prompt\": \"You are an expert software engineer. Output only code unless asked to explain.\"\n}\n</code></pre>"},{"location":"agents/codex.html#setup","title":"Setup","text":""},{"location":"agents/codex.html#authentication","title":"Authentication","text":"<pre><code>$env:OPENAI_API_KEY = \"sk-...\"\n</code></pre>"},{"location":"agents/codex.html#verify","title":"Verify","text":"<pre><code>echo $env:OPENAI_API_KEY\n</code></pre>"},{"location":"agents/codex.html#mcp-notes","title":"MCP Notes","text":"<ul> <li>MCP tool integration available</li> <li>better fit for implementation than long-form reasoning</li> <li>low temperature recommended for stable output</li> </ul>"},{"location":"agents/codex.html#notes","title":"Notes","text":"<ul> <li>strong fit for code generation</li> <li>better fit for patches than long architecture narratives</li> <li>useful for review, refactor, and implementation support</li> </ul>"},{"location":"agents/ollama.html","title":"Agent: Ollama","text":""},{"location":"agents/ollama.html#purpose","title":"Purpose","text":"<ul> <li>local inference</li> <li>offline usage</li> <li>lightweight analysis</li> <li>local model experimentation</li> </ul>"},{"location":"agents/ollama.html#when-to-use","title":"When to Use","text":"<ul> <li>offline environment</li> <li>low-cost local inference</li> <li>local log summary</li> <li>simple repeated analysis</li> </ul>"},{"location":"agents/ollama.html#model-options","title":"Model Options","text":"Model Strength Typical Use <code>llama3.2</code> general reasoning summary, general analysis <code>mistral</code> fast response quick log check <code>codellama</code> code-oriented simple code draft <code>deepseek-r1</code> deeper reasoning more complex local analysis"},{"location":"agents/ollama.html#configuration","title":"Configuration","text":"<pre><code>{\n  \"agent\": \"ollama\",\n  \"model\": \"llama3.2\",\n  \"base_url\": \"http://localhost:11434\",\n  \"temperature\": 0.7,\n  \"stream\": false\n}\n</code></pre>"},{"location":"agents/ollama.html#setup","title":"Setup","text":""},{"location":"agents/ollama.html#windows","title":"Windows","text":"<pre><code>irm https://ollama.com/install.ps1 | iex\n</code></pre> <p>or</p> <pre><code>winget install Ollama.Ollama\n</code></pre>"},{"location":"agents/ollama.html#linux-macos","title":"Linux / macOS","text":"<pre><code>curl -fsSL https://ollama.com/install.sh | sh\n</code></pre>"},{"location":"agents/ollama.html#pull-model","title":"Pull Model","text":"<pre><code>ollama pull llama3.2\nollama list\n</code></pre>"},{"location":"agents/ollama.html#verify-api","title":"Verify API","text":"<pre><code>curl http://localhost:11434/api/tags\n</code></pre>"},{"location":"agents/ollama.html#mcp-notes","title":"MCP Notes","text":"<ul> <li>local runtime required</li> <li>Ollama should be running before MCP server usage</li> <li>suitable for local tool support and lightweight analysis</li> </ul>"},{"location":"agents/ollama.html#notes","title":"Notes","text":"<ul> <li>strong fit for Local AI role</li> <li>better fit for support analysis than complex architecture planning</li> <li>WSL2 can access <code>localhost:11434</code></li> </ul>"},{"location":"architecture/system-design.html","title":"System Design","text":""},{"location":"architecture/system-design.html#scope","title":"Scope","text":"<ul> <li>AI Agent structure</li> <li>MCP connection model</li> <li>GitHub integration model</li> <li>CI/CD/CT automation path</li> </ul>"},{"location":"architecture/system-design.html#ai-agents","title":"AI Agents","text":"Agent Main Role Main AI Agent code generation, document updates, task structure Sub AI Agent review, test result analysis, issue and PR follow-up Local AI Agent optional local helper, repeated execution support, environment side tasks <p>Notes:</p> <ul> <li>role split first</li> <li>deployment shape second</li> <li>fixed product mapping not required</li> </ul> <p>Examples:</p> <ul> <li>Main: Claude or Codex</li> <li>Sub: Codex or Claude</li> <li>Local: Ollama</li> </ul>"},{"location":"architecture/system-design.html#remote-ai-agents","title":"Remote AI Agents","text":""},{"location":"architecture/system-design.html#responsibility","title":"Responsibility","text":"<ul> <li>code generation</li> <li>document writing</li> <li>task split</li> <li>review</li> <li>test result analysis</li> <li>GitHub follow-up</li> </ul>"},{"location":"architecture/system-design.html#deployment","title":"Deployment","text":"<ul> <li>baseline</li> <li>one Remote AI Agent</li> <li>optional extension</li> <li>add Local AI Agent</li> </ul>"},{"location":"architecture/system-design.html#practical-model","title":"Practical Model","text":"<ul> <li>one Remote AI Agent can perform both Main AI and Sub AI roles</li> <li>separate Main AI and Sub AI is an operating model, not a hard requirement</li> </ul>"},{"location":"architecture/system-design.html#local-ai-agents","title":"Local AI Agents","text":""},{"location":"architecture/system-design.html#characteristics","title":"Characteristics","text":"<ul> <li>optional component</li> <li>local execution support</li> <li>partial Sub AI replacement possible</li> </ul>"},{"location":"architecture/system-design.html#examples","title":"Examples","text":"<ul> <li>Ollama</li> <li>MLX</li> <li>vLLM</li> </ul>"},{"location":"architecture/system-design.html#usage","title":"Usage","text":"<ul> <li>remote API cost reduction</li> <li>repeated local test support</li> <li>local log and file based analysis support</li> </ul>"},{"location":"architecture/system-design.html#system-diagram","title":"System Diagram","text":"<pre><code>graph TD\n    subgraph UserLayer[\"User / IDE\"]\n        User[\"User\"]\n        VSCode[\"VS Code\"]\n    end\n\n    subgraph Agents[\"AI Agents\"]\n        MainAI[\"Main AI Agent\"]\n        SubAI[\"Sub AI Agent\"]\n        LocalAI[\"Local AI Agent\"]\n    end\n\n    subgraph MCP[\"MCP Layer\"]\n        Gateway[\"VS Code MCP Gateway\"]\n        LocalMCP[\"Local MCP Server\"]\n        GitHubMCP[\"GitHub MCP Server\"]\n    end\n\n    subgraph Automation[\"Automation\"]\n        GHA[\"GitHub Actions\"]\n        Jenkins[\"Jenkins\"]\n        Bridge[\"Python Bridge\"]\n    end\n\n    subgraph GitHub[\"GitHub\"]\n        Issue[\"Issue\"]\n        PR[\"Pull Request\"]\n        Actions[\"Actions\"]\n    end\n\n    User --&gt; VSCode\n    VSCode --&gt; MainAI\n    VSCode --&gt; SubAI\n    VSCode --&gt; LocalAI\n\n    MainAI --&gt; Gateway\n    SubAI --&gt; Gateway\n    LocalAI --&gt; Gateway\n\n    Gateway --&gt; LocalMCP\n    Gateway --&gt; GitHubMCP\n\n    Issue --&gt; GHA\n    Issue --&gt; Jenkins\n    GHA --&gt; Bridge\n    Jenkins --&gt; Bridge\n    Bridge --&gt; LocalMCP\n\n    GitHubMCP --&gt; Issue\n    GitHubMCP --&gt; PR\n    GitHubMCP --&gt; Actions</code></pre>"},{"location":"architecture/system-design.html#ai-agent-working","title":"AI Agent Working","text":"Step Work Type Owner 1 task structure Main AI 2 code and document generation Main AI 3 review and risk check Sub AI 4 local tool execution Local MCP Server or Local AI 5 test result analysis Sub AI 6 Issue and PR follow-up GitHub MCP Server or automation 7 final decision User <p>Notes:</p> <ul> <li>execution layer and analysis layer split</li> <li>one Remote AI Agent can cover step 1, 2, 3, 5, and 6 together</li> </ul>"},{"location":"architecture/system-design.html#agent-interference","title":"Agent Interference","text":"<ul> <li>direct overlap minimization</li> <li>JSON, log, and comment based handoff</li> <li>execution result first</li> <li>analysis result second</li> </ul> <pre><code>Local MCP execution\n  -&gt; result.json + log\n  -&gt; analysis\n  -&gt; code or document update\n</code></pre>"},{"location":"architecture/system-design.html#cicdct-automation","title":"CI/CD/CT Automation","text":""},{"location":"architecture/system-design.html#scope_1","title":"Scope","text":"<ul> <li>CI automation</li> <li>Pull Request, Review, Actions follow-up</li> <li>CD automation</li> <li>workflow based delivery path</li> <li>CT automation</li> <li>Local MCP tool based test execution</li> <li>JSON, log, comment trace</li> </ul>"},{"location":"architecture/system-design.html#github-issue-based-entry","title":"GitHub Issue Based Entry","text":"Request Type Label Template Execution Path Main Purpose Runner TEST Request <code>test-request-runner</code> <code>test_request_runner.yml</code> GitHub Actions -&gt; self-hosted runner runner based automated test execution Direct TEST Request <code>test-request-direct</code> <code>test_request_direct.yml</code> Jenkins -&gt; direct MCP execution direct local test execution General Issue / PR normal workflow standard templates GitHub MCP Server, AI Agent, GitHub Actions review, update, tracking"},{"location":"architecture/system-design.html#automation-components","title":"Automation Components","text":"<ul> <li>GitHub Actions</li> <li>runner TEST Request execution</li> <li>self-hosted runner integration</li> <li>artifact and comment trace</li> <li>Jenkins</li> <li>direct TEST Request execution</li> <li>webhook trigger</li> <li>requested ref checkout</li> <li>Python Bridge</li> <li>issue body parsing</li> <li>selected tool mapping</li> <li>Local MCP Server call</li> <li>JSON and Markdown result generation</li> </ul>"},{"location":"architecture/system-design.html#issue-based-flow","title":"Issue Based Flow","text":"<pre><code>runner test request issue\n  -&gt; GitHub Actions\n  -&gt; self-hosted runner\n  -&gt; Python bridge\n  -&gt; mcp-server-local-runner\n\ndirect test request issue\n  -&gt; Jenkins\n  -&gt; Python bridge\n  -&gt; mcp-server-local-direct\n</code></pre> <pre><code>GitHub Issue / PR\n  -&gt; GitHub Actions or Jenkins\n  -&gt; Python bridge\n  -&gt; Local MCP Server\n  -&gt; JSON / log / comment\n  -&gt; GitHub traceability\n</code></pre>"},{"location":"architecture/system-design.html#main-flows","title":"Main Flows","text":""},{"location":"architecture/system-design.html#direct-mcp-flow","title":"Direct MCP Flow","text":"<pre><code>AI Agent or local client\n  -&gt; VS Code MCP Gateway\n  -&gt; mcp-server-local-direct\n  -&gt; local tools\n  -&gt; log files + tool result payload\n</code></pre>"},{"location":"architecture/system-design.html#runner-test-request-flow","title":"Runner Test Request Flow","text":"<pre><code>GitHub Issue\n  -&gt; GitHub Actions workflow\n  -&gt; self-hosted runner\n  -&gt; mcp.scripts.run_test_request\n  -&gt; mcp-server-local-runner\n  -&gt; selected tools\n  -&gt; results JSON + logs\n  -&gt; GitHub Issue comment\n</code></pre> <p>Related:</p> <ul> <li>.github/workflows/test_request_local.yaml</li> <li>.github/ISSUE_TEMPLATE/test_request_runner.yml</li> </ul>"},{"location":"architecture/system-design.html#direct-test-request-flow","title":"Direct Test Request Flow","text":"<pre><code>GitHub Issue\n  -&gt; Jenkins webhook trigger\n  -&gt; mcp.scripts.run_test_request\n  -&gt; mcp-server-local-direct\n  -&gt; selected tools\n  -&gt; results JSON + logs\n  -&gt; GitHub Issue comment\n</code></pre> <p>Related:</p> <ul> <li>Jenkinsfile</li> <li>.github/ISSUE_TEMPLATE/test_request_direct.yml</li> </ul>"},{"location":"architecture/system-design.html#component-details","title":"Component Details","text":""},{"location":"architecture/system-design.html#vs-code-mcp-gateway","title":"VS Code MCP Gateway","text":"<ul> <li>VS Code internal</li> <li>MCP Server connection</li> <li>tool discovery</li> <li>tool routing</li> </ul> <p>Reference:</p> <ul> <li>MCP Gateway</li> </ul>"},{"location":"architecture/system-design.html#local-mcp-server","title":"Local MCP Server","text":"<ul> <li>local process</li> <li>build, flash, test, log tools</li> <li>direct mode</li> <li>runner mode</li> </ul> <p>Reference:</p> <ul> <li>MCP Server-Local</li> </ul>"},{"location":"architecture/system-design.html#github-mcp-server","title":"GitHub MCP Server","text":"<ul> <li>local process + GitHub API integration</li> <li>Issue, Pull Request, Review, Actions access</li> <li>no local execution hosting</li> </ul> <p>Reference:</p> <ul> <li>MCP Server-GitHub</li> </ul>"},{"location":"architecture/system-design.html#python-bridge","title":"Python Bridge","text":"<ul> <li>repository script layer</li> <li>issue body parsing</li> <li>tool mapping</li> <li>server mode selection</li> <li>result JSON generation</li> <li>Markdown comment generation</li> </ul> <p>Target scripts:</p> <ul> <li><code>mcp/scripts/run_test_request.py</code></li> <li><code>mcp/scripts/make_test_result.py</code></li> </ul>"},{"location":"architecture/system-design.html#installation-locations","title":"Installation Locations","text":"Component Location Entry VS Code MCP Gateway VS Code internal VS Code feature Local MCP Server Local process Python module GitHub MCP Server Local process GitHub API integration GitHub Actions GitHub runner workflow Jenkins Jenkins agent webhook trigger Local AI Local host runtime Remote AI cloud or local CLI provider dependent"},{"location":"architecture/system-design.html#design-principles","title":"Design Principles","text":"<ul> <li>simple execution path first</li> <li>clear split between <code>direct</code> and <code>runner</code></li> <li>GitHub collaboration and local execution separation</li> <li>JSON, log, Markdown comment trace</li> <li>Local AI stays optional</li> <li>role split does not require fixed process split</li> </ul>"},{"location":"architecture/system-design.html#related","title":"Related","text":"<ul> <li>Claude</li> <li>Codex</li> <li>Ollama</li> <li>MCP Gateway</li> <li>MCP Server-Local</li> <li>MCP Server-GitHub</li> <li>OpenClaw WSL2 Setup</li> </ul>"},{"location":"envs/github_self_hosted_runner.html","title":"Self-hosted Runner","text":"<p>References:</p> <ul> <li>GitHub-hosted runners     https://docs.github.com/ko/actions/reference/runners/github-hosted-runners</li> <li>Self-hosted runners     https://docs.github.com/ko/actions/reference/runners/self-hosted-runners</li> </ul>"},{"location":"envs/github_self_hosted_runner.html#overview","title":"Overview","text":"<p><code>Target Runner</code>\uc640 GitHub <code>self-hosted runner</code>\uc758 \uad00\uacc4  </p> <p>\ud575\uc2ec \uac1c\ub150:   - <code>Target Runner</code>\ub294 TEST \uc694\uccad\uc744 \ucc98\ub9ac\ud560 \uc2e4\ud589 \uc8fc\uccb4\ub97c \uac00\ub9ac\ud0a4\ub294 \ub17c\ub9ac\uc801 \uc774\ub984         - \uc774 \uc2e4\ud589 \uc8fc\uccb4\ub294 GitHub Actions\uc758 <code>self-hosted runner</code>\uc77c \uc218\ub3c4 \uc788\uace0, \uc6d0\uaca9 worker / lab node / \uc804\uc6a9 \ud14c\uc2a4\ud2b8 \uba38\uc2e0\uc77c \uc218\ub3c4 \uc788\ub2e4    - \ud604\uc7ac \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 <code>Target Runner</code>\ub97c \ub354 \ub113\uc740 \uac1c\ub150\uc73c\ub85c \uc0ac\uc6a9\ud558\ub418, \uac00\ub2a5\ud558\uba74 GitHub runner label\uacfc \uac19\uc740 \uc774\ub984\uc73c\ub85c \ub9de\ucd98\ub2e4 </p> <p>\uc989:   - \ubb38\uc11c \uc124\uacc4 \uad00\uc810: <code>Target Runner</code> = TEST \uc694\uccad\uc744 \ub2f4\ub2f9\ud560 \uc2e4\ud589 \ub178\ub4dc   - GitHub Actions \uad00\uc810: <code>self-hosted runner</code> = GitHub\uac00 job\uc744 \ubcf4\ub0b4\ub294 \uc2e4\ud589 \ub178\ub4dc</p>"},{"location":"envs/github_self_hosted_runner.html#quick-start","title":"Quick Start","text":"<p>\ub0b4 PC\ub97c \uc5f0\uacb0\ud558\ub824\uba74 \uc544\ub798 \uc21c\uc11c\ub85c \uc9c4\ud589\ud558\uba74 \ub41c\ub2e4.</p> <ol> <li>GitHub \uc800\uc7a5\uc18c\uc758 <code>Settings &gt; Actions &gt; Runners</code>\ub85c \uc774\ub3d9.</li> <li><code>New self-hosted runner</code>\ub97c runner \ub4f1\ub85d \uba85\ub839 (\ub4f1\ub85d\uc744 Token \uacfc \ucd5c\uc2e0 Action Download)         </li> <li>\uc124\uce58 Manaul \uacfc \uc124\uc815 Manaul (Token \ud655\uc778)              </li> <li>Runner image : Window/Linux/MacOS \uc120\ud0dd </li> <li>Architecture : x86</li> <li>Self-hosted Runner \uc124\uc815 (<code>config.cmd</code>)<ul> <li>Group : default </li> </ul> </li> <li><code>runs-on</code>\uc5d0 <code>self-hosted</code>\uc640 \ud574\ub2f9 label\uc744 \uc9c0\uc815.</li> </ol> <p>\uc774 \ud504\ub85c\uc81d\ud2b8 \uae30\uc900\uc73c\ub85c\ub294 <code>Target Runner: local-dev</code>\uc640 runner label <code>local-dev</code>\ub97c \ub9de\ucd94\ub294 \ubc29\uc2dd\uc744 \uad8c\uc7a5\ud55c\ub2e4.</p> <p></p> <pre><code>\u221a Connected to GitHub\n\nCurrent runner version: '2.333.1'\n2026-04-20 05:30:21Z: Listening for Jobs\n</code></pre>"},{"location":"envs/github_self_hosted_runner.html#recommended-naming","title":"Recommended Naming","text":"<p>\ub0b4 PC\ub97c self-hosted runner\ub85c \ubd99\uc77c \ub54c\ub294 runner label\uc744 <code>Target Runner</code>\uc640 \uac19\uc740 \uac12\uc73c\ub85c \ub9de\ucd94\ub294 \uac83\uc774 \uac00\uc7a5 \ub2e8\uc21c\ud558\ub2e4.</p> <p>\uc608:</p> <ul> <li>\ub0b4 PC \uc774\ub984 \uc5ed\ud560: <code>local-dev</code></li> <li>GitHub runner label: <code>local-dev</code></li> <li>TEST \uc774\uc288\uc758 <code>Target Runner</code>: <code>local-dev</code></li> </ul> <p>\uc774\ub807\uac8c \ud558\uba74 \uc774\uc288 \uc6b4\uc601\uacfc Actions \ub77c\uc6b0\ud305\uc774 \uac19\uc740 \uae30\uc900\uc73c\ub85c \uc6c0\uc9c1\uc778\ub2e4.</p> <p>\uad8c\uc7a5 \uc608\uc2dc:</p>"},{"location":"envs/github_self_hosted_runner.html#connect-my-pc","title":"Connect My PC","text":""},{"location":"envs/github_self_hosted_runner.html#1-prepare-runner-directory","title":"1. Prepare Runner Directory","text":"<p>\uc774 \ubb38\uc11c\uc5d0\uc11c\ub294 runner \uc791\uc5c5 \ud3f4\ub354\ub97c repository \ub0b4\ubd80\uc5d0 \ub450\ub294 \ubc29\uc2dd\uc744 \uae30\uc900\uc73c\ub85c \uc124\uba85\ud55c\ub2e4.</p> <p>\uc608:</p> <pre><code>cd D:\\works\\projects\\local-ai-agent-mcp\nmkdir action-runner\ncd .\\action-runner\n</code></pre> <p>\uad8c\uc7a5 \uc774\uc720:</p> <ul> <li>\uc774 \ud504\ub85c\uc81d\ud2b8\uc640 runner \uad00\ub828 \ud30c\uc77c \uc704\uce58\ub97c \uac19\uc774 \uad00\ub9ac\ud558\uae30 \uc27d\ub2e4</li> <li>\ub85c\uceec \ubb38\uc11c\uc640 \uc2e4\uc81c \uc791\uc5c5 \uacbd\ub85c\uac00 \uc77c\uce58\ud55c\ub2e4</li> <li>\ud14c\uc2a4\ud2b8\uc6a9 \uc2a4\ud06c\ub9bd\ud2b8\ub098 \ub85c\uadf8 \uacbd\ub85c\ub97c repository \uae30\uc900\uc73c\ub85c \uc124\uba85\ud558\uae30 \ud3b8\ud558\ub2e4</li> </ul> <p>\uc8fc\uc758:</p> <ul> <li><code>action-runner</code> \ud3f4\ub354\ub294 \ubcf4\ud1b5 Git\uc73c\ub85c \ucd94\uc801\ud558\uc9c0 \uc54a\ub294\ub2e4</li> <li>\ud544\uc694\ud558\uba74 <code>.gitignore</code>\uc5d0 \ucd94\uac00\ud574\uc11c \uad00\ub9ac\ud55c\ub2e4</li> </ul>"},{"location":"envs/github_self_hosted_runner.html#2-get-registration-commands-from-github","title":"2. Get Registration Commands from GitHub","text":"<p>\uc800\uc7a5\uc18c \uae30\uc900:</p> <ul> <li><code>Settings</code></li> <li><code>Actions</code></li> <li><code>Runners</code></li> <li><code>New self-hosted runner</code></li> </ul> <p>action/runner version \ud655\uc778 https://github.com/actions/runner/releases</p>"},{"location":"envs/github_self_hosted_runner.html#3-set-runner-name-and-labels","title":"3. Set Runner Name and Labels","text":"<p><code>config.cmd</code> \uc2e4\ud589 \uc911 \uc544\ub798 \ud56d\ubaa9\uc744 \ubb3b\ub294\ub2e4.</p> <ul> <li>runner group</li> <li>runner name</li> <li>labels</li> <li>service\ub85c \uc124\uce58\ud560\uc9c0 \uc5ec\ubd80</li> </ul> Target Runner[] Meaning <code>local-dev_00</code> \uac1c\ubc1c\uc790\uac00 \uc9c1\uc811 \uad00\ub9ac\ud558\ub294 \ub85c\uceec \uc2e4\ud589 \ud658\uacbd <code>qemu-runner</code> \uc5d0\ubbac\ub808\uc774\uc158 \uae30\ubc18 \ud14c\uc2a4\ud2b8 \uc804\uc6a9 \ud658\uacbd <code>lab-node-01</code> \ud2b9\uc815 \uc7a5\ube44\uc2e4/\ud558\ub4dc\uc6e8\uc5b4 \ub178\ub4dc <code>windows-hw-01</code> Windows \uae30\ubc18 \uc2e4\uc7a5\ube44 \ud14c\uc2a4\ud2b8 \ub178\ub4dc <ul> <li>\ubc18\ub4dc\uc2dc \uad00\ub9ac\uc790 \uad8c\ud55c </li> </ul> <pre><code>--------------------------------------------------------------------------------\n|        ____ _ _   _   _       _          _        _   _                      |\n|       / ___(_) |_| | | |_   _| |__      / \\   ___| |_(_) ___  _ __  ___      |\n|      | |  _| | __| |_| | | | | '_ \\    / _ \\ / __| __| |/ _ \\| '_ \\/ __|     |\n|      | |_| | | |_|  _  | |_| | |_) |  / ___ \\ (__| |_| | (_) | | | \\__ \\     |\n|       \\____|_|\\__|_| |_|\\__,_|_.__/  /_/   \\_\\___|\\__|_|\\___/|_| |_|___/     |\n|                                                                              |\n|                       Self-hosted runner registration                        |\n|                                                                              |\n--------------------------------------------------------------------------------\n\n# Authentication\n\n\n\u221a Connected to GitHub\n\n# Runner Registration\n\nEnter the name of the runner group to add this runner to: [press Enter for Default] \n\nEnter the name of runner: [press Enter for JHLEE] local-dev_00\n\nThis runner will have the following labels: 'self-hosted', 'Windows', 'X64'\nEnter any additional labels (ex. label-1,label-2): [press Enter to skip] local-dev\n\n\u221a Runner successfully added\n\n# Runner settings\n\nEnter name of work folder: [press Enter for _work]\n\n\u221a Settings Saved.\n\nWould you like to run the runner as service? (Y/N) [press Enter for N]\n</code></pre> <pre><code>runner name: my-pc\nlabels: self-hosted, Windows, X64, local-dev\n</code></pre> <p>\ud575\uc2ec\uc740 \uae30\ubcf8 label \uc678\uc5d0 <code>local-dev</code> \uac19\uc740 \ud504\ub85c\uc81d\ud2b8\uc6a9 label\uc744 \ucd94\uac00\ud558\ub294 \uac83\uc774\ub2e4.</p>"},{"location":"envs/github_self_hosted_runner.html#4-choose-how-to-run-it","title":"4. Choose How to Run It","text":"<p>\uc77c\ud68c\uc131 \ud655\uc778\uc740 repository \ub0b4\ubd80\uc758 <code>action-runner</code> \ud3f4\ub354\uc5d0\uc11c \ucf58\uc194 \uc2e4\ud589\uc73c\ub85c \ucda9\ubd84\ud558\ub2e4.</p> <pre><code>.\\run.cmd\n</code></pre> <p>PC\ub97c \ucf24 \ub54c\ub9c8\ub2e4 \uc790\ub3d9\uc73c\ub85c \ubd99\uac8c \ud558\ub824\uba74 \uac19\uc740 \ud3f4\ub354\uc5d0\uc11c \uc11c\ube44\uc2a4 \uc124\uce58\ub97c \ud574\ub450\ub294 \ud3b8\uc774 \uc88b\ub2e4.</p> <pre><code>.\\svc install\n.\\svc start\n</code></pre> <p>\uc11c\ube44\uc2a4\ub85c \uc2e4\ud589\ud558\uba74 \ub85c\uadf8\uc544\uc6c3 \ud6c4\uc5d0\ub3c4 runner\uac00 \uacc4\uc18d \ub300\uae30\ud560 \uc218 \uc788\ub2e4.</p>"},{"location":"envs/github_self_hosted_runner.html#5-verify-runner-status-in-github","title":"5. Verify Runner Status in GitHub","text":"<p>\ub4f1\ub85d\uc774 \ub05d\ub098\uba74 <code>Settings &gt; Actions &gt; Runners</code> \ud654\uba74\uc5d0 runner\uac00 <code>Idle</code> \ub610\ub294 <code>Online</code> \uc0c1\ud0dc\ub85c \ubcf4\uc5ec\uc57c \ud55c\ub2e4.</p> <p>\ubcf4\uc774\uc9c0 \uc54a\uc73c\uba74 \ubcf4\ud1b5 \uc544\ub798\ub97c \ud655\uc778\ud558\uba74 \ub41c\ub2e4.</p> <ul> <li>\ubc29\ud654\ubcbd \ub610\ub294 \ud504\ub85d\uc2dc \uc81c\ud55c</li> <li>\ud1a0\ud070 \ub9cc\ub8cc \ud6c4 \ub4f1\ub85d \uc2e4\ud328</li> <li><code>run.cmd</code> \ub610\ub294 \uc11c\ube44\uc2a4\uac00 \uc2e4\uc81c\ub85c \uc2e4\ud589 \uc911\uc778\uc9c0</li> <li>label\uc774 \uae30\ub300\ud55c \uac12\uc73c\ub85c \ub4e4\uc5b4\uac14\ub294\uc9c0</li> </ul>"},{"location":"envs/github_self_hosted_runner.html#workflow-mapping","title":"Workflow Mapping","text":"<p>runner\ub97c \ubd99\uc5ec\ub3c4 workflow\uac00 \uadf8 runner\ub97c \uc0ac\uc6a9\ud558\ub3c4\ub85d \uc9c0\uc815\ud558\uc9c0 \uc54a\uc73c\uba74 \uc2e4\uc81c job\uc740 \ub0b4\ub824\uc624\uc9c0 \uc54a\ub294\ub2e4.</p> <p>\uc608\ub97c \ub4e4\uc5b4 \ub0b4 PC label\uc774 <code>local-dev</code>\ub77c\uba74:</p> <pre><code>jobs:\n  test-on-local-dev:\n    runs-on: [self-hosted, local-dev]\n    steps:\n      - uses: actions/checkout@v4\n      - name: Show runner\n        run: echo \"running on self-hosted local-dev\"\n</code></pre> <p><code>runs-on: [self-hosted, local-dev]</code>\ub294 <code>self-hosted</code>\uc774\uba74\uc11c <code>local-dev</code> label\uc744 \uac00\uc9c4 runner\ub9cc \uc7a1\uaca0\ub2e4\ub294 \ub73b\uc774\ub2e4.</p>"},{"location":"envs/github_self_hosted_runner.html#current-repository-status","title":"Current Repository Status","text":"<p>\ud604\uc7ac \uc800\uc7a5\uc18c\uc758 workflow\ub294 <code>.github/workflows/github_pages.yaml</code> \ud558\ub098\uc774\uba70, \uc774 \ud30c\uc77c\uc740 <code>ubuntu-latest</code>\ub97c \uc0ac\uc6a9\ud55c\ub2e4.</p> <p>\uc989 \uc9c0\uae08 \uc0c1\ud0dc\uc5d0\uc11c\ub294 \ub0b4 PC\ub97c self-hosted runner\ub85c \ub4f1\ub85d\ud574\ub3c4 \uc790\ub3d9\uc73c\ub85c \uc0ac\uc6a9\ub418\uc9c0\ub294 \uc54a\ub294\ub2e4. \uc2e4\uc81c\ub85c \uc0ac\uc6a9\ud558\ub824\uba74:</p> <ul> <li>\uc0c8 workflow\ub97c \ucd94\uac00\ud558\uac70\ub098</li> <li>\uae30\uc874 workflow\uc758 <code>runs-on</code>\uc744 self-hosted label \uae30\ubc18\uc73c\ub85c \ubc14\uafd4\uc57c \ud55c\ub2e4</li> </ul>"},{"location":"envs/github_self_hosted_runner.html#issue-based-flow","title":"Issue-Based Flow","text":"<pre><code>GitHub Issue (TEST \uc694\uccad)\n  \u2192 Target Runner \ud655\uc778\n  \u2192 \ud574\ub2f9 Runner / Worker\uac00 \uc694\uccad \ucc98\ub9ac\n  \u2192 Local MCP Tool \uc2e4\ud589\n  \u2192 logs + result.json \uc0dd\uc131\n  \u2192 GitHub Issue \ub313\uae00\ub85c \uacb0\uacfc \ubcf4\uace0\n</code></pre> <p>\uc774 \uad6c\uc870\uc5d0\uc11c\ub294 <code>Target Runner</code>\uac00 \ub2e8\uc21c \uba54\ubaa8\uac00 \uc544\ub2c8\ub77c \uc2e4\uc81c \uc2e4\ud589 \uc18c\uc720\uad8c\uacfc \ub77c\uc6b0\ud305 \uae30\uc900\uc774 \ub41c\ub2e4.</p>"},{"location":"envs/github_self_hosted_runner.html#mapping-strategy","title":"Mapping Strategy","text":"<p>\uad8c\uc7a5 \ub9e4\ud551\uc740 \uc544\ub798\uc640 \uac19\ub2e4.</p> <ul> <li>Issue <code>Target Runner</code>: <code>local-dev</code></li> <li>GitHub Actions self-hosted runner label: <code>local-dev</code></li> </ul> <p>\uc774\ub807\uac8c \ub9de\ucd94\uba74 \uc0ac\ub78c\uc774 \uc774\uc288\ub97c \ubcf4\uace0 \ud310\ub2e8\ud560 \ub54c\ub3c4 \uc27d\uace0, \ub098\uc911\uc5d0 Actions workflow\ub97c \ubd99\uc77c \ub54c\ub3c4 \ud63c\ub3d9\uc774 \uc801\ub2e4.</p>"},{"location":"envs/github_self_hosted_runner.html#multiple-runners","title":"Multiple Runners","text":"<p><code>Target Runner</code>\ub294 \ub2e8\uc77c \uac12\ub9cc \uc0ac\uc6a9\ud560 \uc218\ub3c4 \uc788\uace0, \uc5ec\ub7ec \ud6c4\ubcf4\ub97c \ub458 \uc218\ub3c4 \uc788\ub2e4.</p> <p>\uad8c\uc7a5 \uaddc\uce59:</p> <ul> <li>\uae30\ubcf8\uc740 \ub2e8\uc77c runner</li> <li>\uc5ec\ub7ec runner\uac00 \ud544\uc694\ud558\uba74 \uc27c\ud45c \uad6c\ubd84 \ubaa9\ub85d \uc0ac\uc6a9</li> <li>\uc758\ubbf8\ub294 \uc6b0\uc120 <code>OR</code>\ub85c \ud574\uc11d</li> </ul> <p>\uc608:</p> <pre><code>Target Runner: qemu-runner, lab-node-01\n</code></pre> <p>\uc758\ubbf8:</p> <ul> <li><code>qemu-runner</code> \ub610\ub294 <code>lab-node-01</code> \uc911 \ud558\ub098\uac00 \ucc98\ub9ac \uac00\ub2a5</li> <li>\uba3c\uc800 claim\ud55c \uc2e4\ud589 \uc8fc\uccb4\uac00 \ucc98\ub9ac</li> </ul>"},{"location":"envs/github_self_hosted_runner.html#ownership-rules","title":"Ownership Rules","text":"<p>\uc5ec\ub7ec runner\uac00 \ub3d9\uc2dc\uc5d0 \uc874\uc7ac\ud560 \uacbd\uc6b0 \ucd5c\uc18c\ud55c \uc544\ub798 \uaddc\uce59\uc774 \ud544\uc694\ud558\ub2e4.</p> <ol> <li>TEST \uc694\uccad\uc5d0\ub294 <code>Target Runner</code>\ub97c \uba85\uc2dc\ud55c\ub2e4.</li> <li>\uac01 runner\ub294 \uc790\uc2e0\uc774 \ucc98\ub9ac \uac00\ub2a5\ud55c \uc694\uccad\ub9cc \uc120\ud0dd\ud55c\ub2e4.</li> <li>\ucc98\ub9ac \uc2dc\uc791 \uc2dc assignee \ub610\ub294 label\ub85c claim \uc0c1\ud0dc\ub97c \ub0a8\uae34\ub2e4.</li> <li>\uc644\ub8cc \ud6c4 <code>test-done</code> \ub610\ub294 <code>test-failed</code> \uac19\uc740 \uc0c1\ud0dc\ub97c \uae30\ub85d\ud55c\ub2e4.</li> </ol> <p>\ucd94\ucc9c label \uc608\uc2dc:</p> <ul> <li><code>test-request</code></li> <li><code>test-running</code></li> <li><code>test-done</code></li> <li><code>test-failed</code></li> </ul>"},{"location":"envs/github_self_hosted_runner.html#relationship-with-mcp","title":"Relationship with MCP","text":"<p>self-hosted runner \uc790\uccb4\uac00 \uace7 MCP Server\ub294 \uc544\ub2c8\ub2e4.</p> <p>\uc5ed\ud560\uc740 \ub2e4\ub974\ub2e4.</p> <ul> <li>Runner / Worker: TEST \uc694\uccad\uc744 \uc2e4\uc81c\ub85c \uc218\ud589\ud558\ub294 \uc2e4\ud589 \ud658\uacbd</li> <li>Local MCP Server: \uc2e4\ud589 \ud658\uacbd\uc5d0\uc11c tool\uc744 \ub178\ucd9c\ud558\ub294 \uc778\ud130\ud398\uc774\uc2a4</li> <li>GitHub MCP Server: GitHub Issue/\ub313\uae00/\uc0c1\ud0dc \ubcc0\uacbd\uc744 \ub2e4\ub8e8\ub294 \uc778\ud130\ud398\uc774\uc2a4</li> </ul> <p>\uc989 \uc2e4\uc81c \uad6c\uc870\ub294 \ub2e4\uc74c\uc5d0 \uac00\uae5d\ub2e4.</p> <pre><code>GitHub Issue\n  \u2192 Runner / Worker\n  \u2192 GitHub MCP Server\ub85c \uc694\uccad \ud655\uc778\n  \u2192 Local MCP Server tool \uc2e4\ud589\n  \u2192 \uacb0\uacfc \uc0dd\uc131\n  \u2192 GitHub MCP Server\ub85c \uacb0\uacfc \ubcf4\uace0\n</code></pre>"},{"location":"envs/github_self_hosted_runner.html#recommended-position","title":"Recommended Position","text":"<p>\ud604\uc7ac \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 <code>Target Runner</code>\ub97c \ub2e4\uc74c\ucc98\ub7fc \uc774\ud574\ud558\ub294 \uac83\uc774 \uac00\uc7a5 \uc548\uc804\ud558\ub2e4.</p> <ul> <li>\uc9c0\uae08: self-hosted runner\uc640 \uc720\uc0ac\ud55c \ub17c\ub9ac\uc801 \uc2e4\ud589 \ub178\ub4dc \uc774\ub984</li> <li>\ub098\uc911: \ud544\uc694\ud558\uba74 GitHub Actions self-hosted runner label\uacfc 1:1 \ub9e4\ud551</li> </ul> <p>\ud2b9\ud788 \ub0b4 PC\ub97c runner\ub85c \uc5f0\uacb0\ud560 \ub54c\ub294 <code>local-dev</code> \uac19\uc740 label \ud558\ub098\ub97c \uae30\uc900 \uc774\ub984\uc73c\ub85c \uc815\ud574 \ub450\ub294 \ud3b8\uc774 \uc6b4\uc601\uc0c1 \uac00\uc7a5 \ud3b8\ud558\ub2e4.</p>"},{"location":"envs/github_self_hosted_runner.html#related","title":"Related","text":"<ul> <li>github_templates.md \u2014 Issue / PR / TEST \uc694\uccad \ud15c\ud50c\ub9bf</li> <li>mcp_server_local.md \u2014 Local MCP Server\uc640 TEST \uc694\uccad \ud750\ub984</li> <li>mcp_server_github.md \u2014 GitHub MCP Server \uc5ed\ud560</li> </ul>"},{"location":"envs/github_templates.html","title":"GitHub Templates","text":""},{"location":"envs/github_templates.html#overview","title":"Overview","text":"<ul> <li>GitHub Issue templates</li> <li>Pull Request template</li> <li>GitHub Actions automation entry</li> <li>TEST request structure</li> </ul> <p>Key point:</p> <ul> <li>this document is not only about templates</li> <li>the main purpose is GitHub Action Automation based on Issue input</li> </ul>"},{"location":"envs/github_templates.html#automation-first","title":"Automation First","text":""},{"location":"envs/github_templates.html#main-automation-paths","title":"Main Automation Paths","text":"Path Trigger Main Engine Purpose Runner TEST Request GitHub Issue with <code>test-request-runner</code> GitHub Actions self-hosted runner based TEST automation Direct TEST Request GitHub Issue with <code>test-request-direct</code> Jenkins or AI Agent direct MCP execution request Docs Site Publish repository event GitHub Actions GitHub Pages publish"},{"location":"envs/github_templates.html#workflow-files","title":"Workflow Files","text":"Workflow File Role Test Request Local Runner <code>.github/workflows/test_request_local.yaml</code> Issue based TEST automation on self-hosted runner GitHub Pages <code>.github/workflows/github_pages.yaml</code> documentation build and publish <p>Notes:</p> <ul> <li>workflow count: <code>2</code></li> <li>the TEST request flow is the operationally important GitHub Actions automation path</li> <li>the Pages workflow is the documentation delivery path</li> </ul>"},{"location":"envs/github_templates.html#template-list","title":"Template List","text":"Template File Purpose Bug Report <code>.github/ISSUE_TEMPLATE/bug_report.md</code> reproducible bug report Documentation <code>.github/ISSUE_TEMPLATE/documentation.md</code> documentation update request Feature Request <code>.github/ISSUE_TEMPLATE/feature_request.md</code> feature addition or improvement request Question <code>.github/ISSUE_TEMPLATE/question.md</code> question or clarification Test Request Direct <code>.github/ISSUE_TEMPLATE/test_request_direct.yml</code> direct MCP execution request Test Request Runner <code>.github/ISSUE_TEMPLATE/test_request_runner.yml</code> GitHub Actions runner based TEST request Pull Request <code>.github/pull_request_template.md</code> change summary and review context"},{"location":"envs/github_templates.html#test-request-templates","title":"TEST Request Templates","text":""},{"location":"envs/github_templates.html#purpose","title":"Purpose","text":"<ul> <li>TEST execution request</li> <li>ref based execution request</li> <li>result trace through JSON, log, and Issue comment</li> </ul>"},{"location":"envs/github_templates.html#files","title":"Files","text":"<ul> <li>.github/ISSUE_TEMPLATE/test_request_direct.yml</li> <li>.github/ISSUE_TEMPLATE/test_request_runner.yml</li> </ul>"},{"location":"envs/github_templates.html#shared-fields","title":"Shared Fields","text":"<ul> <li><code>Template Version</code></li> <li><code>Target Runner</code></li> <li><code>Branch / Tag / Commit</code></li> <li><code>MCP Server Mode</code></li> <li>setup tool checklist</li> <li>test tool checklist</li> <li>log tool checklist</li> </ul>"},{"location":"envs/github_templates.html#current-split","title":"Current Split","text":"Request Type Label Execution Path Notes Runner <code>test-request-runner</code> GitHub Actions -&gt; self-hosted runner -&gt; <code>mcp-server-local-runner</code> GitHub Actions automation path Direct <code>test-request-direct</code> Jenkins or AI Agent -&gt; <code>mcp-server-local-direct</code> direct execution path"},{"location":"envs/github_templates.html#example","title":"Example","text":"<pre><code>## Request Ref\n- Template Version: v0.0.1\n- Branch / Tag / Commit: main\n- Target Runner: local-dev\n- MCP Server Mode: runner\n\n## Test Tool\n- [x] test_ping_00\n- [ ] test_ping_11\n- [ ] test_ping_22\n\n## Log Tool\n- [x] get_serial_log\n- [x] log_analyzer\n- [ ] log_snapshot\n</code></pre>"},{"location":"envs/github_templates.html#runner-automation","title":"Runner Automation","text":""},{"location":"envs/github_templates.html#flow","title":"Flow","text":"<pre><code>GitHub Issue\n  -&gt; label: test-request-runner\n  -&gt; GitHub Actions\n  -&gt; self-hosted runner\n  -&gt; mcp.scripts.run_test_request\n  -&gt; mcp-server-local-runner\n  -&gt; results JSON + logs\n  -&gt; issue comment\n</code></pre>"},{"location":"envs/github_templates.html#related-files","title":"Related Files","text":"<ul> <li>.github/workflows/test_request_local.yaml</li> <li>.github/ISSUE_TEMPLATE/test_request_runner.yml</li> </ul>"},{"location":"envs/github_templates.html#characteristics","title":"Characteristics","text":"<ul> <li>GitHub Actions driven</li> <li>self-hosted runner required</li> <li>artifact upload included</li> <li>result comment generation included</li> </ul>"},{"location":"envs/github_templates.html#direct-execution","title":"Direct Execution","text":""},{"location":"envs/github_templates.html#flow_1","title":"Flow","text":"<pre><code>GitHub Issue\n  -&gt; label: test-request-direct\n  -&gt; Jenkins or AI Agent\n  -&gt; mcp.scripts.run_test_request\n  -&gt; mcp-server-local-direct\n  -&gt; results JSON + logs\n  -&gt; issue comment\n</code></pre>"},{"location":"envs/github_templates.html#related-files_1","title":"Related Files","text":"<ul> <li>.github/ISSUE_TEMPLATE/test_request_direct.yml</li> <li>Jenkinsfile</li> </ul>"},{"location":"envs/github_templates.html#characteristics_1","title":"Characteristics","text":"<ul> <li>direct MCP mode</li> <li>execution owner selected by <code>Target Runner</code></li> <li>GitHub Actions workflow is not the main engine in this path</li> </ul>"},{"location":"envs/github_templates.html#title-rule","title":"Title Rule","text":"<pre><code>[TEST] [&lt;mcp mode&gt;] &lt;YYYY-MM-DD HH:MM&gt;\n[TEST] [&lt;mcp mode&gt;] [&lt;target runner&gt;] &lt;YYYY-MM-DD HH:MM&gt;\n</code></pre> <p>Examples:</p> <pre><code>[TEST] [direct] 2026-04-20 16:30\n[TEST] [runner] [local-dev] 2026-04-20 16:35\n</code></pre>"},{"location":"envs/github_templates.html#target-runner","title":"Target Runner","text":""},{"location":"envs/github_templates.html#runner-template-examples","title":"Runner Template Examples","text":"<ul> <li><code>local-dev</code></li> </ul>"},{"location":"envs/github_templates.html#direct-template-examples","title":"Direct Template Examples","text":"<ul> <li><code>jenkins</code></li> <li><code>ai-agent</code></li> </ul> <p>Notes:</p> <ul> <li>runner template target values are tied to self-hosted runner selection</li> <li>direct template target values are execution owner values</li> </ul> <p>Reference:</p> <ul> <li>GitHub Self Hosted Runner</li> </ul>"},{"location":"envs/github_templates.html#usage-guidance","title":"Usage Guidance","text":""},{"location":"envs/github_templates.html#use-bug-report-when","title":"Use Bug Report When","text":"<ul> <li>a defect needs reproduction and tracking</li> </ul>"},{"location":"envs/github_templates.html#use-feature-request-when","title":"Use Feature Request When","text":"<ul> <li>a change proposal or feature idea is needed</li> </ul>"},{"location":"envs/github_templates.html#use-test-request-when","title":"Use TEST Request When","text":"<ul> <li>a specific ref needs execution</li> <li>logs and JSON output are needed</li> <li>execution trace must remain on GitHub</li> </ul> <p>Key point:</p> <ul> <li>TEST Request is an execution request</li> <li>Pull Request is a code change request</li> </ul>"},{"location":"envs/github_templates.html#pull-request-template","title":"Pull Request Template","text":"<p>File:</p> <ul> <li>.github/pull_request_template.md</li> </ul> <p>Typical contents:</p> <ul> <li>change summary</li> <li>key updates</li> <li>test result summary</li> <li>related document updates</li> </ul>"},{"location":"envs/github_templates.html#recommended-labels","title":"Recommended Labels","text":"<ul> <li><code>test-request-runner</code></li> <li><code>test-request-direct</code></li> <li><code>test-running</code></li> <li><code>test-done</code></li> <li><code>test-failed</code></li> </ul>"},{"location":"envs/github_templates.html#directory-structure","title":"Directory Structure","text":"<pre><code>.github/\n  ISSUE_TEMPLATE/\n    bug_report.md\n    documentation.md\n    feature_request.md\n    question.md\n    test_request_direct.yml\n    test_request_runner.yml\n  pull_request_template.md\n  workflows/\n    github_pages.yaml\n    test_request_local.yaml\n</code></pre>"},{"location":"envs/github_templates.html#related","title":"Related","text":"<ul> <li>GitHub Self Hosted Runner</li> <li>MCP Server-Local</li> <li>MCP Server-GitHub</li> <li>MCP Gateway</li> <li>System Design</li> </ul>"},{"location":"envs/openclaw_wsl2_setup.html","title":"Experiment: OpenClaw Setup on WSL2","text":""},{"location":"envs/openclaw_wsl2_setup.html#status","title":"Status","text":"<ul> <li>optional</li> <li>experiment</li> <li>not required for the default document flow</li> </ul>"},{"location":"envs/openclaw_wsl2_setup.html#goal","title":"Goal","text":"<p>Windows 11 + WSL2(Ubuntu) \ud658\uacbd\uc5d0\uc11c OpenClaw\ub97c \uc124\uce58\ud558\uace0 \ub3d9\uc791\uc744 \uac80\uc99d\ud55c\ub2e4.</p> <p>\uae30\ubcf8 \uacbd\ub85c\uac00 \uc544\ub2cc \uc120\ud0dd \uc2e4\ud5d8 \ud56d\ubaa9\uc774\ub2e4.</p>"},{"location":"envs/openclaw_wsl2_setup.html#environment","title":"Environment","text":"\ud56d\ubaa9 \uac12 OS Windows 11 Pro WSL Version WSL2 Distribution Ubuntu Type optional experiment"},{"location":"envs/openclaw_wsl2_setup.html#setup-steps","title":"Setup Steps","text":""},{"location":"envs/openclaw_wsl2_setup.html#step-1-enter-wsl2-ubuntu","title":"Step 1: Enter WSL2 Ubuntu","text":"<pre><code>wsl -d Ubuntu\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#step-2-install-nodejs-24","title":"Step 2: Install Node.js 24","text":"<pre><code>curl -fsSL https://fnm.vercel.app/install | bash\nsource ~/.bashrc\n\nfnm install 24\nfnm use 24\nnode -v\nnpm -v\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#step-3-install-openclaw","title":"Step 3: Install OpenClaw","text":"<pre><code>curl -fsSL https://openclaw.ai/install.sh | bash\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#step-4-authenticate-claude-cli","title":"Step 4: Authenticate Claude CLI","text":"<p>Claude CLI\ub97c \uc0ac\uc6a9\ud558\ub294 \uacbd\uc6b0 \uc778\uc99d\uc774 \ud544\uc694\ud558\ub2e4.</p> <p>Reference:</p> <ul> <li>claude.md - Setup</li> </ul> <p>Option A:</p> <pre><code>cp /mnt/c/Users/ahyuo/.claude/.credentials ~/.claude/.credentials\n</code></pre> <p>Option B:</p> <pre><code>echo 'export ANTHROPIC_API_KEY=\"sk-ant-...\"' &gt;&gt; ~/.bashrc\nsource ~/.bashrc\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#step-5-onboarding","title":"Step 5: Onboarding","text":"<p>General:</p> <pre><code>openclaw onboard --install-daemon\n</code></pre> <p>Skip channel:</p> <pre><code>openclaw onboard --install-daemon --skip-channels\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#step-6-verify-gateway","title":"Step 6: Verify Gateway","text":"<pre><code>openclaw config get gateway.token\nopenclaw gateway status --token &lt;token&gt;\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#step-7-open-dashboard","title":"Step 7: Open Dashboard","text":"<pre><code>openclaw dashboard\n</code></pre>"},{"location":"envs/openclaw_wsl2_setup.html#checklist","title":"Checklist","text":"<ul> <li> WSL2 Ubuntu \ud655\uc778</li> <li> Node.js 24 \uc124\uce58</li> <li> OpenClaw \uc124\uce58</li> <li> Claude CLI \uc778\uc99d</li> <li> <code>openclaw onboard</code> \uc644\ub8cc</li> <li> <code>openclaw gateway status</code> \ud655\uc778</li> <li> dashboard \uc811\uc18d \ud655\uc778</li> </ul>"},{"location":"envs/openclaw_wsl2_setup.html#notes","title":"Notes","text":"<ul> <li>optional setup</li> <li>experiment only</li> <li>\uae30\ubcf8 \ubb38\uc11c \ud750\ub984\uc758 \ud544\uc218 \ud56d\ubaa9 \uc544\ub2d8</li> </ul>"},{"location":"mcp/mcp_gateway.html","title":"MCP Gateway","text":""},{"location":"mcp/mcp_gateway.html#overview","title":"Overview","text":"<ul> <li>VS Code internal MCP Gateway</li> <li>multiple MCP Server connections</li> <li>tool routing and tool discovery</li> <li>Local MCP Server + GitHub MCP Server bridge</li> </ul>"},{"location":"mcp/mcp_gateway.html#mcp-purpose","title":"MCP Purpose","text":"<ul> <li>AI Agent to Local Tool connection</li> <li>AI Agent to GitHub resource connection</li> <li>common tool call path</li> <li>execution layer and collaboration layer split</li> </ul>"},{"location":"mcp/mcp_gateway.html#ai-agent-connection-purpose","title":"AI Agent Connection Purpose","text":"<ul> <li>shell command dependency reduction</li> <li>common interface for build, flash, test, log tools</li> <li>unified access to Issue, Pull Request, Review, Actions</li> <li>agent role based tool selection</li> </ul>"},{"location":"mcp/mcp_gateway.html#deployment-note","title":"Deployment Note","text":"<ul> <li>Reference model</li> <li>Main AI, Sub AI, Local AI role split</li> <li>Practical model</li> <li>one Remote AI Agent can cover Main AI + Sub AI together</li> <li>Local AI is optional</li> <li>Interpretation</li> <li>role split is a documentation model</li> <li>runtime deployment can use 1, 2, or 3 agents</li> </ul>"},{"location":"mcp/mcp_gateway.html#role","title":"Role","text":"Component Location Role VS Code MCP Gateway VS Code internal MCP Server connection, tool discovery, tool routing MCP Server-Local Local <code>build_tool</code>, <code>flash_tool</code>, <code>do_test_*</code>, <code>log_analyzer</code>, <code>test_result</code> MCP Server-GitHub Local Process + Remote GitHub API <code>pr_*</code>, <code>issue_*</code>, <code>repo_*</code>, <code>workflow_*</code>"},{"location":"mcp/mcp_gateway.html#current-usage","title":"Current Usage","text":"<ol> <li>VS Code reads <code>.vscode/mcp.json</code>.</li> <li>VS Code connects MCP servers.</li> <li>AI Agent selects tools by task.</li> <li>Gateway routes the call to the matched MCP Server.</li> </ol> <p>Notes:</p> <ul> <li>VS Code MCP Gateway is a connection hub.</li> <li>It is not a full workflow engine.</li> <li>end-to-end CT orchestration still needs workflow logic outside the gateway.</li> </ul>"},{"location":"mcp/mcp_gateway.html#routing-rules","title":"Routing Rules","text":"Tool Prefix Target Server <code>build_*</code>, <code>flash_*</code>, <code>do_test_*</code> Local MCP Server <code>uart_capture</code>, <code>qemu_spawn</code>, <code>reg_dump</code>, <code>file_read</code> Local MCP Server <code>log_analyzer</code>, <code>test_result</code> Local MCP Server <code>github_*</code>, <code>pr_*</code>, <code>issue_*</code>, <code>repo_*</code>, <code>commit_*</code>, <code>workflow_*</code> GitHub MCP Server"},{"location":"mcp/mcp_gateway.html#protocol-flow","title":"Protocol Flow","text":"<pre><code>sequenceDiagram\n    participant A as AI Agent\n    participant G as VS Code MCP Gateway\n    participant L as Local MCP Server\n    participant GH as GitHub MCP Server\n\n    A-&gt;&gt;G: tools/call { name, arguments }\n    G-&gt;&gt;G: match tool routing\n\n    alt Local Tool\n        G-&gt;&gt;L: tools/call\n        L--&gt;&gt;G: result\n    else GitHub Tool\n        G-&gt;&gt;GH: tools/call\n        GH--&gt;&gt;G: result\n    else Unknown Tool\n        G--&gt;&gt;A: tool_not_found\n    end\n\n    G--&gt;&gt;A: result</code></pre>"},{"location":"mcp/mcp_gateway.html#gateway-scope","title":"Gateway Scope","text":"<ul> <li>covered</li> <li>MCP Server connection</li> <li>tool discovery</li> <li>tool call routing</li> <li>not covered</li> <li>GitHub event webhook receive</li> <li>result polling</li> <li>automatic result analysis chaining</li> <li>automatic final report posting</li> </ul>"},{"location":"mcp/mcp_gateway.html#agent-tool-access","title":"Agent Tool Access","text":"Agent Tool Access Target Gateway Path Local AI <code>build_tool</code>, <code>flash_tool</code>, <code>do_test_*</code> Gateway -&gt; Local MCP Server Sub AI <code>log_analyzer</code>, <code>test_result</code> Gateway -&gt; Local MCP Server Sub AI <code>pr_*</code>, <code>issue_*</code>, <code>workflow_*</code> Gateway -&gt; GitHub MCP Server Main AI optional, usually code and document focused optional <p>Notes:</p> <ul> <li>This table is a role reference.</li> <li>One Remote AI Agent can handle both Main AI and Sub AI responsibilities.</li> <li>A single Remote AI Agent can use GitHub tools and result analysis tools together.</li> <li>Local AI is an optional helper, not a mandatory deployment unit.</li> </ul>"},{"location":"mcp/mcp_gateway.html#cicdct-relation","title":"CI/CD/CT Relation","text":""},{"location":"mcp/mcp_gateway.html#direct-mcp-path","title":"Direct MCP Path","text":"<pre><code>AI Agent\n  -&gt; VS Code MCP Gateway\n  -&gt; Local MCP Server or GitHub MCP Server\n</code></pre>"},{"location":"mcp/mcp_gateway.html#github-issue-based-ct-path","title":"GitHub Issue Based CT Path","text":"<pre><code>GitHub Issue\n  -&gt; GitHub Actions or Jenkins\n  -&gt; Python bridge\n  -&gt; Local MCP Server\n  -&gt; JSON / log / comment\n</code></pre> <p>Notes:</p> <ul> <li><code>test-request-runner</code></li> <li>GitHub Actions + self-hosted runner path</li> <li><code>test-request-direct</code></li> <li>Jenkins direct execution path</li> <li>both paths are outside the VS Code internal gateway scope</li> </ul>"},{"location":"mcp/mcp_gateway.html#related","title":"Related","text":"<ul> <li>MCP Server-Local</li> <li>MCP Server-GitHub</li> <li>System Design</li> </ul>"},{"location":"mcp/mcp_server_github.html","title":"GitHub MCP Server","text":"<p>\ud604\uc7ac \uc548\uc4f0\uc784 \uc635\uc158 </p>"},{"location":"mcp/mcp_server_github.html#references","title":"References","text":"<ul> <li>Manual: https://docs.github.com/en/copilot/how-tos/provide-context/use-mcp-in-your-ide/use-the-github-mcp-server</li> <li>Node.js server: https://github.com/github/github-mcp-server</li> </ul>"},{"location":"mcp/mcp_server_github.html#overview","title":"Overview","text":"<p>GitHub MCP Server\ub294 VS Code \uac19\uc740 MCP Client\uc5d0\uc11c GitHub \uc790\uc6d0\uc744 \uc77d\uace0 \uc4f0\uae30 \uc704\ud55c MCP Server.</p> <p>\ud604\uc7ac \uc800\uc7a5\uc18c \uae30\uc900 \uc5ed\ud560:</p> <ul> <li>GitHub Repository, Issue, Pull Request, Actions \uc815\ubcf4 \uc870\ud68c</li> <li>GitHub Issue, comment, label, assignee \uac19\uc740 \ud611\uc5c5 \uc815\ubcf4 \uac31\uc2e0</li> <li>Local MCP Server \uae30\ubc18 TEST \ud750\ub984\uc758 GitHub \uce21 \uc5f0\uacc4</li> </ul> <p>\uc9c1\uc811 Local test tool\uc744 \uc2e4\ud589\ud558\ub294 \uc8fc\uccb4\ub294 \uc544\ub2d8.</p>"},{"location":"mcp/mcp_server_github.html#current-position-in-this-repository","title":"Current Position In This Repository","text":"<p>\ud604\uc7ac \uc790\ub3d9 TEST \ud750\ub984:</p> <pre><code>GitHub Issue\n  -&gt; GitHub Actions\n  -&gt; Python bridge\n  -&gt; Local MCP Server\n  -&gt; results/logs/mcp/server_local + results JSON\n  -&gt; GitHub Issue comment\n</code></pre> <p>\uc758\ubbf8:</p> <ul> <li>GitHub MCP Server: GitHub \uce21 \uc870\ud68c / \uac31\uc2e0 \ub2f4\ub2f9</li> <li>Local MCP Server: \uc2e4\uc81c tool \uc2e4\ud589 \ub2f4\ub2f9</li> <li>GitHub Actions: Issue \uae30\ubc18 \uc790\ub3d9\ud654 bridge \ub2f4\ub2f9</li> </ul> <p>\uc989 \ud604\uc7ac \uad6c\uc870\uc5d0\uc11c GitHub MCP Server\ub294 Local tool \uc2e4\ud589 \uacbd\ub85c\ub97c \uc9c1\uc811 host \ud558\uac70\ub098 trigger \ud558\ub294 \uc8fc\uccb4\uac00 \uc544\ub2c8\ub77c, GitHub \uc5f0\uacc4 \uc5ed\ud560\uc5d0 \uc9d1\uc911.</p>"},{"location":"mcp/mcp_server_github.html#flow","title":"Flow","text":"<pre><code>flowchart LR\n    A[\"GitHub Issue\"] --&gt; B[\"GitHub Actions\"]\n    B --&gt; C[\"Python bridge&lt;br/&gt;mcp.scripts.run_test_request\"]\n    C --&gt; D[\"Local MCP Server\"]\n    D --&gt; E[\"results/logs/mcp/server_local&lt;br/&gt;results/*.json\"]\n    B --&gt; F[\"GitHub Issue comment\"]\n    D --&gt; E</code></pre>"},{"location":"mcp/mcp_server_github.html#vs-code-configuration","title":"VS Code Configuration","text":"<p>VS Code MCP server setup \uc608\uc2dc:</p> <pre><code>{\n  \"servers\": {\n    \"io.github.github/github-mcp-server\": {\n      \"type\": \"http\",\n      \"url\": \"https://api.githubcopilot.com/mcp/\",\n      \"gallery\": \"https://api.mcp.github.com\",\n      \"version\": \"0.33.0\"\n    }\n  },\n  \"inputs\": []\n}\n</code></pre>"},{"location":"mcp/mcp_server_github.html#example-startup-log","title":"Example Startup Log","text":"<pre><code>2026-04-17 10:33:22.770 [info] Starting server io.github.github/github-mcp-server\n2026-04-17 10:33:22.770 [info] Connection state: Starting\n2026-04-17 10:33:22.770 [info] Starting server from LocalProcess extension host\n2026-04-17 10:33:22.771 [info] Connection state: Running\n2026-04-17 10:33:25.037 [info] Discovered resource metadata at https://api.githubcopilot.com/.well-known/oauth-protected-resource/mcp/\n2026-04-17 10:33:25.037 [info] Using auth server metadata url: https://github.com/login/oauth\n2026-04-17 10:33:25.440 [info] Discovered authorization server metadata at https://github.com/.well-known/oauth-authorization-server/login/oauth\n2026-04-17 10:33:33.737 [info] Discovered 44 tools\n</code></pre>"},{"location":"mcp/mcp_server_github.html#main-capabilities","title":"Main Capabilities","text":"<p>\uc8fc\uc694 capability group:</p> <ul> <li>Repository \uc870\ud68c / \uac80\uc0c9</li> <li>branch, commit, file \uc870\ud68c</li> <li>Issue \uc0dd\uc131 / \uc218\uc815 / label / assignee / comment \ucc98\ub9ac</li> <li>Pull Request \uc870\ud68c / diff / review / merge \ucc98\ub9ac</li> <li>GitHub Actions run / job / step / log \uc870\ud68c</li> </ul> <p>\uc2e4\ubb34 \uad00\uc810\uc5d0\uc11c\ub294 GitHub \uce21 control plane \uc5ed\ud560.</p>"},{"location":"mcp/mcp_server_github.html#roles","title":"Roles","text":"No. Role Group Example Tasks Verification 1 <code>Repository Metadata</code> \uc800\uc7a5\uc18c \uc815\ubcf4, default branch \uc870\ud68c Inferred 2 <code>Repository Search</code> \uc811\uadfc \uac00\ub2a5\ud55c \uc800\uc7a5\uc18c \uac80\uc0c9 Inferred 3 <code>Branch Search</code> branch \uac80\uc0c9, \uae30\uc900 branch \uc120\ud0dd Inferred 4 <code>File Fetch</code> \ud2b9\uc815 ref \ud30c\uc77c \uc870\ud68c Inferred 5 <code>Blob Fetch</code> blob SHA \uae30\ubc18 \uc870\ud68c Inferred 6 <code>Commit Fetch</code> \ub2e8\uc77c commit \uba54\ud0c0\ub370\uc774\ud130, \ubcc0\uacbd \ub0b4\uc6a9 \uc870\ud68c Inferred 7 <code>Commit Compare</code> \ub450 ref \uac04 \ubcc0\uacbd \ud30c\uc77c, \ud1b5\uacc4 \ube44\uad50 Inferred 8 <code>Commit Search</code> commit \uac80\uc0c9 Inferred 9 <code>Commit Status</code> combined status, check \uacb0\uacfc \uc870\ud68c Inferred 10 <code>Workflow Run Lookup</code> \ud2b9\uc815 commit\uc758 Actions run \uc870\ud68c Inferred 11 <code>Workflow Jobs</code> run \ub0b4\ubd80 job \ubaa9\ub85d \uc870\ud68c Inferred 12 <code>Workflow Steps</code> job step \uc0c1\ud0dc \uc870\ud68c Inferred 13 <code>Workflow Logs</code> \uc2e4\ud328 job log \uc870\ud68c Inferred 14 <code>PR Metadata</code> PR \uc81c\ubaa9, \uc0c1\ud0dc, base/head branch \uc870\ud68c Inferred 15 <code>PR Diff</code> PR diff, patch \uc870\ud68c Inferred 16 <code>PR Patch By File</code> \ud30c\uc77c \ub2e8\uc704 PR patch \uc870\ud68c Inferred 17 <code>PR File List</code> \ubcc0\uacbd \ud30c\uc77c \ubaa9\ub85d \uc870\ud68c Inferred 18 <code>PR Discussion</code> PR comment, review comment, review event \uc870\ud68c Inferred 19 <code>PR Reviews</code> review \ubaa9\ub85d \uc870\ud68c Inferred 20 <code>PR Review Threads</code> inline review thread, resolve \uc0c1\ud0dc \uc870\ud68c Inferred 21 <code>PR Reactions</code> reaction \uc870\ud68c, \ucd94\uac00 Inferred 22 <code>PR Comment Reply</code> inline review comment reply \uc791\uc131 Inferred 23 <code>PR Review Submit</code> approve, request changes, review \uc81c\ucd9c Inferred 24 <code>PR Reviewer Request</code> reviewer, team reviewer \uc694\uccad Inferred 25 <code>PR Ready/Draft</code> Draft, Ready for Review \uc804\ud658 Inferred 26 <code>PR Update</code> \uc81c\ubaa9, \ubcf8\ubb38, \uc0c1\ud0dc, base branch \uc218\uc815 Inferred 27 <code>PR Merge</code> merge, squash, rebase \uc2e4\ud589 Inferred 28 <code>PR Auto Merge</code> auto-merge \uc124\uc815 Inferred 29 <code>Issue Fetch</code> Issue \ubcf8\ubb38, \uc0c1\ud0dc, \uba54\ud0c0\ub370\uc774\ud130 \uc870\ud68c Inferred 30 <code>Issue Comments</code> Issue comment \uc870\ud68c Inferred 31 <code>Issue Create</code> Issue \uc0dd\uc131 Inferred 32 <code>Issue Update</code> \uc81c\ubaa9, \ubcf8\ubb38, \uc0c1\ud0dc, milestone \uc218\uc815 Inferred 33 <code>Issue Labels</code> label \ucd94\uac00, \uc81c\uac70 Inferred 34 <code>Issue Assignees</code> assignee \ucd94\uac00, \uc81c\uac70 Inferred 35 <code>Issue Lock</code> conversation lock, unlock Inferred 36 <code>Issue Comment Update</code> top-level comment \uc218\uc815 Inferred 37 <code>Issue Reactions</code> Issue comment reaction \ucc98\ub9ac Inferred 38 <code>File Create</code> \ud30c\uc77c \uc0dd\uc131 Inferred 39 <code>File Update</code> \ud30c\uc77c \uc218\uc815 Inferred 40 <code>File Delete</code> \ud30c\uc77c \uc0ad\uc81c Inferred 41 <code>Blob Create</code> blob \uc0dd\uc131 Inferred 42 <code>Tree Create</code> Git tree \uc0dd\uc131 Inferred 43 <code>Commit Create</code> Git commit \uc0dd\uc131 Inferred 44 <code>Ref Update</code> branch ref \uc774\ub3d9, branch \uc0dd\uc131 Inferred"},{"location":"mcp/mcp_server_github.html#practical-grouping","title":"Practical Grouping","text":"Group Included Capabilities Read <code>Repository</code>, <code>File</code>, <code>Commit</code>, <code>PR</code>, <code>Issue</code> \uc870\ud68c Search <code>Repository</code>, <code>Branch</code>, code, <code>PR</code>, <code>Issue</code>, <code>Commit</code> \uac80\uc0c9 Collaboration <code>Review</code>, comment, reaction, label, assignee CI / Verification <code>Actions</code> run, job, step, log Write \ud30c\uc77c \uc0dd\uc131 / \uc218\uc815 / \uc0ad\uc81c, branch, commit, merge"},{"location":"mcp/mcp_server_github.html#role-separation","title":"Role Separation","text":"<p>\ud604\uc7ac \uc5ed\ud560 \ubd84\ub9ac:</p> <ul> <li>GitHub MCP Server</li> <li>GitHub \uc0c1\ud0dc \uc870\ud68c</li> <li>Issue / comment / review / Actions \uacb0\uacfc \uc870\ud68c \ubc0f \uac31\uc2e0</li> <li>Local MCP Server</li> <li><code>build_tool</code>, <code>flash_tool</code>, <code>log_analyzer</code> \uac19\uc740 local tool \uc2e4\ud589</li> <li>log file, result JSON \uc800\uc7a5</li> <li>GitHub Actions</li> <li>Issue event\uc640 Local MCP \uc2e4\ud589 \uacbd\ub85c \uc5f0\uacb0</li> </ul> <p>\uc774 \uad6c\ubd84\uc774 \uc911\uc694\ud55c \uc774\uc720\ub294, IDE \uc548\uc5d0 GitHub MCP Server\uac00 \uc788\uc5b4\ub3c4 Issue \uae30\ubc18 Local TEST\ub294 workflow runner \uc758\uc874\uc131\uc774 \ub0a8\ub294\ub2e4\ub294 \uc810\uc744 \uc124\uba85\ud558\uae30 \ub54c\ubb38.</p>"},{"location":"mcp/mcp_server_github.html#related","title":"Related","text":"<ul> <li>mcp_server_local.md</li> <li>mcp_gateway.md</li> <li>github_templates.md</li> <li>github_self_hosted_runner.md</li> </ul>"},{"location":"mcp/mcp_server_local.html","title":"Local MCP Server","text":"<p>\ub85c\uceec \ud658\uacbd\uc5d0\uc11c \uc0ac\uc6a9\ud558\ub294 MCP Server \uad6c\uc870\uc640 GitHub Issue \uae30\ubc18 Test Request \ud750\ub984\uc744 \uc815\ub9ac\ud55c \ubb38\uc11c\ub2e4.</p>"},{"location":"mcp/mcp_server_local.html#overview","title":"Overview","text":"<p>\ud604\uc7ac \uc800\uc7a5\uc18c\ub294 \ud558\ub098\uc758 \uacf5\ud1b5 Local MCP core \uc704\uc5d0 \ub450 \uac1c\uc758 entrypoint\ub97c \ub454\ub2e4.</p> <ul> <li><code>mcp.server_local_direct.server</code></li> <li><code>mcp.server_local_runner.server</code></li> </ul> <p>\uacf5\ud1b5 runtime \uacfc tool \uc815\uc758\ub294 <code>mcp/server_local/</code> \uc544\ub798\uc5d0 \uc788\ub2e4.</p> <pre><code>mcp/\n\u251c\u2500\u2500 scripts/\n\u2502   \u251c\u2500\u2500 make_test_result.py\n\u2502   \u2514\u2500\u2500 run_test_request.py\n\u251c\u2500\u2500 server_local/\n\u2502   \u251c\u2500\u2500 runtime.py\n\u2502   \u2514\u2500\u2500 toolsets.py\n\u251c\u2500\u2500 server_local_direct/\n\u2502   \u2514\u2500\u2500 server.py\n\u2514\u2500\u2500 server_local_runner/\n    \u2514\u2500\u2500 server.py\n</code></pre> <p>\ud575\uc2ec \ucc28\uc774\ub294 codebase \uac00 \uc544\ub2c8\ub77c \uc2dc\uc791 \ubc29\uc2dd\uc774\ub2e4.</p> Mode Start Main Context <code>direct</code> VS Code MCP client \uac00 \uc9c1\uc811 \uc2e4\ud589 \ub85c\uceec \uac1c\ubc1c, direct MCP test <code>runner</code> GitHub Actions issue flow \uc5d0\uc11c self-hosted runner \ub97c \ud1b5\ud574 \uc2e4\ud589 GitHub Issue \uae30\ubc18 \uc790\ub3d9 test"},{"location":"mcp/mcp_server_local.html#current-flows-direct","title":"Current Flows - direct","text":"<p>\uc774 \uacbd\ub85c\ub294 GitHub Actions \ub098 self-hosted runner \uac00 \ud544\uc694 \uc5c6\ub2e4.</p> <pre><code>VS Code MCP Gateway\n  -&gt; mcp-server-local-direct\n  -&gt; local MCP tools\n  -&gt; log files + tool result payload\n</code></pre> <p>\uc8fc\uc694 \ubaa9\uc801:</p> <ul> <li>\ub85c\uceec \uac1c\ubc1c</li> <li>direct MCP client test</li> <li>manual tool \ud655\uc778</li> </ul> <p>Entrypoint:</p> <ul> <li><code>python -m mcp.server_local_direct.server</code></li> </ul> <p>VS Code \uc124\uc815 \uc608\uc2dc:</p> <pre><code>{\n  \"servers\": {\n    \"mcp-server-local-direct\": {\n      \"type\": \"stdio\",\n      \"command\": \"python\",\n      \"args\": [\"-m\", \"mcp.server_local_direct.server\"],\n      \"cwd\": \"${workspaceFolder}\"\n    }\n  }\n}\n</code></pre>"},{"location":"mcp/mcp_server_local.html#flow","title":"Flow","text":"<pre><code>flowchart LR\n    A[\"VS Code MCP Gateway\"] --&gt; B[\"mcp-server-local-direct\"]\n    B --&gt; C[\"Local tools\"]\n    C --&gt; D[\"log files + tool result payload\"]</code></pre>"},{"location":"mcp/mcp_server_local.html#current-flows-runner","title":"Current Flows - runner","text":"<p>\uc774 \uacbd\ub85c\ub294 GitHub Actions \uc640 self-hosted runner \uac00 \ud544\uc694\ud558\ub2e4.</p> <pre><code>GitHub Issue\n  -&gt; GitHub Actions workflow\n  -&gt; Python bridge (mcp.scripts.run_test_request)\n  -&gt; mcp-server-local-direct or mcp-server-local-runner\n  -&gt; results/logs/mcp/server_local + results/*.json\n  -&gt; GitHub Issue comment\n</code></pre> <p>\ud604\uc7ac workflow:</p> <ul> <li><code>.github/workflows/test_request_local.yaml</code></li> </ul> <p>\ud604\uc7ac runner requirement:</p> <ul> <li><code>runs-on: [self-hosted, local-dev]</code></li> </ul> <p>\uc989 issue \uae30\ubc18 test \uc694\uccad\uc740 <code>local-dev</code> \ub77c\ubca8\uc744 \uac00\uc9c4 self-hosted runner \uac00 online \uc0c1\ud0dc\uc77c \ub54c \ub3d9\uc791\ud55c\ub2e4.</p> <p>\uc911\uc694\ud55c \uc810:</p> <ul> <li><code>server_local_direct</code> \uc790\uccb4\ub294 GitHub Actions \uc5c6\uc774\ub3c4 \uc2e4\ud589 \uac00\ub2a5</li> <li>\ud558\uc9c0\ub9cc <code>Issue -&gt; Action -&gt; result comment</code> \uacbd\ub85c\ub294 workflow \uac00 self-hosted runner \uc704\uc5d0\uc11c \ub3d9\uc791\ud558\ubbc0\ub85c runner \uac00 \ud544\uc694</li> </ul>"},{"location":"mcp/mcp_server_local.html#flow_1","title":"Flow","text":"<pre><code>flowchart LR\n    A[\"GitHub Issue&lt;br/&gt;Test Request\"] --&gt; B[\"GitHub Actions\"]\n    B --&gt; D[\"Self-hosted Runner&lt;br/&gt;[self-hosted, local-dev]\"]\n    D --&gt; E[\"Python bridge&lt;br/&gt;mcp.scripts.run_test_request\"]\n    E --&gt; F[\"mcp-server-local-direct&lt;br/&gt;or&lt;br/&gt;mcp-server-local-runner\"]\n    F --&gt; G[\"selected tools\"]\n    G --&gt; I[\"results/logs/mcp/server_local&lt;br/&gt;results/*.json\"]\n    I --&gt; C[\"GitHub MCP Server\"]\n    C --&gt; H[\"Comment result on issue\"]</code></pre>"},{"location":"mcp/mcp_server_local.html#flow-decision","title":"Flow Decision","text":"<p><code>direct</code> \ub97c \uc4f0\ub294 \uacbd\uc6b0:</p> <ul> <li>VS Code \ub098 local client \uc5d0\uc11c Local MCP Server \ub97c \uc9c1\uc811 \ub744\uc6b0\uace0 \uc2f6\uc744 \ub54c</li> <li>GitHub Issue \uc790\ub3d9\ud654\uac00 \ud544\uc694 \uc5c6\uc744 \ub54c</li> <li>server \uc790\uccb4\ub97c \ube60\ub974\uac8c \uac80\uc99d\ud558\uace0 \uc2f6\uc744 \ub54c</li> </ul> <p>issue \uae30\ubc18 runner flow \ub97c \uc4f0\ub294 \uacbd\uc6b0:</p> <ul> <li>GitHub Test Request issue \ub85c \uc2e4\ud589\uc744 \uc2dc\uc791\ud558\uace0 \uc2f6\uc744 \ub54c</li> <li>\uacb0\uacfc\ub97c artifact, JSON, log, issue comment \ub85c \ub0a8\uae30\uace0 \uc2f6\uc744 \ub54c</li> <li>\ud2b9\uc815 self-hosted runner \ub85c \ub77c\uc6b0\ud305\ud558\uace0 \uc2f6\uc744 \ub54c</li> </ul>"},{"location":"mcp/mcp_server_local.html#test-request-flow","title":"Test Request Flow","text":"<p>\ud604\uc7ac \uc790\ub3d9 Test Request \ud750\ub984:</p> <pre><code>GitHub Issue\n  -&gt; test_request_local.yaml\n  -&gt; mcp.scripts.run_test_request\n  -&gt; selected local MCP server\n  -&gt; selected tools\n  -&gt; results JSON + log files\n  -&gt; GitHub Issue result comment\n</code></pre>"},{"location":"mcp/mcp_server_local.html#request-source","title":"Request Source","text":"<p>issue body format source:</p> <ul> <li><code>.github/ISSUE_TEMPLATE/test_request_direct.yml</code></li> <li><code>.github/ISSUE_TEMPLATE/test_request_runner.yml</code></li> </ul> <p>\ud604\uc7ac template \uc8fc\uc694 \ud56d\ubaa9:</p> <ul> <li><code>Template Version</code></li> <li><code>Target Runner</code></li> <li><code>Branch / Tag / Commit</code></li> <li>category checklist</li> <li><code>Setup Tools Checklist</code></li> <li><code>Test Tools Checklist</code></li> <li><code>Log Tools Checklist</code></li> </ul> <p>\uad00\ub828 \ubb38\uc11c:</p> <ul> <li>github_templates.md</li> </ul>"},{"location":"mcp/mcp_server_local.html#python-bridge","title":"Python Bridge","text":"<p>bridge script:</p> <ul> <li><code>mcp/scripts/run_test_request.py</code></li> </ul> <p>\uc5ed\ud560:</p> <ol> <li>issue body parsing</li> <li><code>MCP Server Mode</code> \uac80\uc99d</li> <li><code>runner</code> mode \uc77c \ub54c <code>Target Runner</code> \uac80\uc99d</li> <li>\uccb4\ud06c\ub41c category \uc640 tool \ubaa9\ub85d \ud574\uc11d</li> <li>Local MCP Server subprocess \uc2e4\ud589</li> <li>MCP tool \ud638\ucd9c</li> <li>result JSON \uc800\uc7a5</li> <li>workflow \uac00 \ucd5c\uc885 issue comment \ub97c \ub2ec \uc218 \uc788\ub3c4\ub85d \uacb0\uacfc \uc81c\uacf5</li> </ol> <p>\uc2e4\ud589 \ubc29\uc2dd:</p> <ul> <li><code>run_test_request.py</code> \ub294 tool \uc744 \uc9c1\uc811 \uc2e4\ud589\ud558\uc9c0 \uc54a\uc74c</li> <li><code>resolve_server_module()</code> \ub85c \uc120\ud0dd\ub41c mode \uc5d0 \ub530\ub77c server module \uacb0\uc815</li> <li><code>direct</code> \uba74 <code>mcp.server_local_direct.server</code></li> <li><code>runner</code> \uba74 <code>mcp.server_local_runner.server</code></li> <li>\uc774\ud6c4 <code>call_local_mcp()</code> \uc5d0\uc11c <code>python -m &lt;server module&gt;</code> \ud615\ud0dc\ub85c subprocess \uc2e4\ud589</li> <li>\ud45c\uc900\uc785\ub825(stdin) \uc73c\ub85c JSON-RPC \uc694\uccad \uc804\ub2ec</li> <li>\uc694\uccad \uc21c\uc11c:</li> <li><code>initialize</code></li> <li><code>notifications/initialized</code></li> <li><code>tools/list</code></li> <li><code>tools/call</code></li> <li>\ud45c\uc900\ucd9c\ub825(stdout) \uc73c\ub85c \ubc18\ud658\ub41c <code>tools/call</code> \uc751\ub2f5\uc744 \ud30c\uc2f1\ud574\uc11c \uacb0\uacfc JSON \uacfc issue comment payload \uc0dd\uc131</li> </ul> <p>\uc989 \uc2e4\uc81c runner flow \ub294 \ub2e4\uc74c\ucc98\ub7fc \ub3d9\uc791\ud55c\ub2e4.</p> <pre><code>run_test_request.py\n  -&gt; mcp.server_local_runner.server subprocess \uc2e4\ud589\n  -&gt; JSON-RPC \uc694\uccad \uc804\uc1a1\n  -&gt; tool execution result \uc218\uc2e0\n  -&gt; results/Github-ISSUE-TR-&lt;issue_number&gt;.json \uc800\uc7a5\n</code></pre> <pre><code>flowchart LR\n    A[\"run_test_request.py\"] --&gt; B[\"resolve_server_module()\"]\n    B --&gt; C[\"mcp.server_local_runner.server&lt;br/&gt;subprocess\"]\n    A --&gt; D[\"JSON-RPC payload \uc0dd\uc131\"]\n    D --&gt; C\n    C --&gt; E[\"initialize\"]\n    C --&gt; F[\"tools/list\"]\n    C --&gt; G[\"tools/call\"]\n    G --&gt; H[\"tool execution result\"]\n    H --&gt; I[\"results/Github-ISSUE-TR-&lt;issue_number&gt;.json\"]\n    H --&gt; J[\"GitHub issue comment payload\"]</code></pre>"},{"location":"mcp/mcp_server_local.html#server-resolution","title":"Server Resolution","text":"<p>\ud604\uc7ac resolution logic:</p> <ul> <li><code>direct</code> -&gt; <code>mcp.server_local_direct.server</code></li> <li><code>runner</code> -&gt; <code>mcp.server_local_runner.server</code></li> </ul> <p>\ud604\uc7ac server name:</p> <ul> <li><code>mcp-server-local-direct</code></li> <li><code>mcp-server-local-runner</code></li> </ul>"},{"location":"mcp/mcp_server_local.html#tool-execution","title":"Tool Execution","text":"<p>\ud604\uc7ac tool set \uc815\uc758 \uc704\uce58:</p> <ul> <li><code>mcp/server_local/toolsets.py</code></li> </ul> <p>\ud604\uc7ac tool catalog \ub294 category \uae30\ubc18\uc73c\ub85c \uad00\ub9ac\ub41c\ub2e4.</p> <ul> <li><code>setup</code></li> <li><code>test</code></li> <li><code>log</code></li> </ul> <p>\uc608\uc2dc tool:</p> <ul> <li><code>check_version</code></li> <li><code>setup_python</code></li> <li><code>flash_tool</code></li> <li><code>test_ping_00</code></li> <li><code>test_ping_11</code></li> <li><code>test_ping_22</code></li> <li><code>get_serial_log</code></li> <li><code>log_analyzer</code></li> <li><code>log_snapshot</code></li> </ul> <p>Test Request template \uc740 \ud55c issue \uc5d0\uc11c \ud558\ub098\uc758 category \ub9cc \uc120\ud0dd\ud558\ub3c4\ub85d \uc124\uacc4\ub418\uc5b4 \uc788\ub2e4.</p> <p>Python bridge \ub294 \uccb4\ud06c\ub41c category \uc548\uc758 tool \ub4e4\uc744 \uc21c\uc11c\ub300\ub85c \uc2e4\ud589\ud558\uace0, \uacb0\uacfc\ub97c \ud558\ub098\uc758 JSON \uc5d0 \uc800\uc7a5\ud55c\ub2e4.</p> <p>\uc804\uccb4 status \uaddc\uce59:</p> <ul> <li>\ubaa8\ub4e0 tool \uc774 \uc131\uacf5\ud558\uba74 <code>success</code></li> <li>\ud558\ub098\ub77c\ub3c4 \uc2e4\ud328\ud558\uba74 <code>error</code></li> </ul>"},{"location":"mcp/mcp_server_local.html#outputs","title":"Outputs","text":"<p>\ud604\uc7ac output directory:</p> <ul> <li><code>results/logs/mcp/server_local/</code></li> <li><code>results/</code></li> </ul> <p>\ud604\uc7ac runtime log \uc608\uc2dc:</p> <ul> <li><code>results/logs/mcp/server_local/runner.log</code></li> <li><code>results/logs/mcp/server_local/runner-check_version.log</code></li> <li><code>results/logs/mcp/server_local/runner-flash_tool.log</code></li> <li><code>results/logs/mcp/server_local/runner-log_analyzer.log</code></li> </ul> <p>\ud604\uc7ac issue result JSON:</p> <ul> <li><code>results/Github-ISSUE-TR-&lt;issue_number&gt;.json</code></li> </ul> <p>\ud604\uc7ac result JSON \uc8fc\uc694 \ud56d\ubaa9:</p> <ul> <li>request metadata</li> <li>template version</li> <li>resolved MCP server</li> <li>selected tools</li> <li>tool \ubcc4 \uc2e4\ud589 \uacb0\uacfc</li> <li>tool \ubcc4 log path</li> </ul> <p>workflow \ub294 \uc774 \ud30c\uc77c\uc744 artifact \ub85c \uc5c5\ub85c\ub4dc\ud558\uace0, formatting \ud6c4 issue comment \ub97c \uc791\uc131\ud55c\ub2e4.</p>"},{"location":"mcp/mcp_server_local.html#current-limitations","title":"Current Limitations","text":"<p>\ud604\uc7ac \uad6c\ud604\uc740 \ud14c\uc2a4\ud2b8 \uc911\uc2ec\uc758 local harness \uc131\uaca9\uc774 \uac15\ud558\ub2e4.</p> <ul> <li>\uc77c\ubd80 tool \uc740 stub \uad6c\ud604</li> <li>log file naming \uc740 timestamp \uae30\ubc18\uc774 \uc544\ub2c8\ub77c tool name \uae30\ubc18</li> <li>issue comment formatting \uc740 workflow script \uc5d0\uc11c \uc218\ud589</li> <li>issue \uae30\ubc18 flow \ub294 self-hosted runner availability \uc5d0 \uc758\uc874</li> </ul> <p>\uc989 \ud604\uc7ac \ud3ec\uc9c0\uc158\uc740 \ub2e4\uc74c\ucc98\ub7fc \ubcf4\ub294 \uac83\uc774 \ub9de\ub2e4.</p> <ul> <li>practical \ud55c Local MCP Server \uae30\ubc18</li> <li>GitHub Issue \uae30\ubc18 test harness</li> <li>\uc774\ud6c4 \uc2e4\uc81c build, flash, log analysis \ub3d9\uc791\uc73c\ub85c \ud655\uc7a5 \uac00\ub2a5\ud55c \uad6c\uc870</li> </ul>"},{"location":"mcp/mcp_server_local.html#related-files","title":"Related Files","text":"<ul> <li>mcp_gateway.md</li> <li>mcp_server_github.md</li> <li>github_templates.md</li> <li>github_self_hosted_runner.md</li> <li>test_request_direct.yml</li> <li>test_request_runner.yml</li> </ul>"}]}